            WriteLiteral(@"        <script>
            function sortTable(tableBodyId, columnIndex) {
                var table = document.getElementById(tableBodyId);
                var rows = Array.from(table.rows);
                var ascending = table.dataset.sortOrder !== ""asc"";

                rows.sort((rowA, rowB) => {
                    var cellA = rowA.cells[columnIndex].innerText.trim();
                    var cellB = rowB.cells[columnIndex].innerText.trim();

                    // Convert numbers for proper sorting
                    var numA = parseFloat(cellA.replace(/[^0-9.-]+/g, """"));
                    var numB = parseFloat(cellB.replace(/[^0-9.-]+/g, """"));

                    let comparison;
                    if (!isNaN(numA) && !isNaN(numB)) {
                        comparison = ascending ? numA - numB : numB - numA;
                    } else {
                        comparison = ascending ? cellA.localeCompare(cellB) : cellB.localeCompare(cellA);
                    }

            ");
            WriteLiteral(@"        return comparison;
                });

                // Append sorted rows back to the table
                rows.forEach(row => table.appendChild(row));

                table.dataset.sortOrder = ascending ? ""asc"" : ""desc"";
            }
        </script>

